SELECT COUNT(*) AS qtd_servidores FROM SERVIDOR S WHERE LOWER(S.CONTRATO) = LOWER('efetivos') AND LOWER(S.AREA_INGRESSO) = LOWER('biologia geral') AND LOWER(S.SIGLA_CAMPUS) = LOWER('gyn') AND SAIU_DO_IFG = FALSE AND EXISTS (SELECT 1 FROM CALC_HORA_AULA_MEDIA C WHERE C.SIAPE = S.PK_SIAPE AND C.ANO = 2024 AND C.SEMESTRE = 2)